#!/usr/bin/env python3
"""
Compression benchmark for Whisper-tiny 2D weight matrices.
Measures bits/weight vs relative Frobenius reconstruction error.

Methods:
  Baselines: fp32, per-row int8/q8, q4 (per-block-32 scale)
  1. k-means scalar codebook (b=2,3,4 bits)
  2. Product quantisation (d=2,4 subvector dims, 256-entry codebook)
  3. Entropy floor: Shannon entropy of q8/q4 indices; actual zlib of q4 bytes
  4. Outlier-aware low-bit: top X% in fp16, rest in q3/q4

Date: 2026-05-24
"""

import struct, json, sys, time, zlib
import numpy as np

np.random.seed(42)

# ── safetensors ─────────────────────────────────────────────────────────────

def load_header(path):
    with open(path, "rb") as f:
        n = struct.unpack("<Q", f.read(8))[0]
        h = json.loads(f.read(n))
    return h, 8 + n

def load_tensor(path, base, info):
    s, e = info["data_offsets"]
    with open(path, "rb") as f:
        f.seek(base + s)
        return np.frombuffer(f.read(e - s), dtype=np.float32).reshape(info["shape"]).copy()

# ── quantisation ─────────────────────────────────────────────────────────────

def q8_per_row(W):
    scale = np.max(np.abs(W), axis=1, keepdims=True) / 127.0
    scale = np.where(scale == 0, 1.0, scale)
    q = np.clip(np.round(W / scale), -127, 127).astype(np.int8)
    W_hat = q.astype(np.float32) * scale
    bits = (W.size * 8 + W.shape[0] * 32) / W.size
    return W_hat, bits

def _q_block(W, levels, scale_bits_per_block, block=32):
    """Generic per-block-32 quantiser. levels = 2^b. Returns W_hat, bits/weight."""
    flat = W.ravel(); n = len(flat)
    pad = (block - n % block) % block
    blocks = np.concatenate([flat, np.zeros(pad, np.float32)]).reshape(-1, block)
    half = (levels - 1) / 2.0
    scale = np.max(np.abs(blocks), axis=1, keepdims=True) / half
    scale = np.where(scale == 0, 1.0, scale)
    b = int(np.log2(levels))
    lo, hi = -int(half) - (1 if levels % 2 == 0 else 0), int(half)
    q = np.clip(np.round(blocks / scale), lo, hi).astype(np.int8)
    W_hat = (q.astype(np.float32) * scale).ravel()[:n].reshape(W.shape)
    bits = (scale_bits_per_block + block * b) / block
    return W_hat, bits

def q4_block32(W):  return _q_block(W, 16, 16)   # 4.5 bits/weight (fp16 scale)
def q3_block32(W):  return _q_block(W, 8,  16)   # 3.5 bits/weight

# ── k-means 1D ──────────────────────────────────────────────────────────────

def kmeans_1d(data, k, max_iter=25, sample=300_000):
    """Lloyd's k-means on 1D float64 data, with optional subsample for large arrays."""
    n = len(data)
    train = data if n <= sample else data[np.random.choice(n, sample, replace=False)]
    idx = np.random.choice(len(train), k, replace=False)
    centers = train[idx].copy()
    prev = None
    for _ in range(max_iter):
        # vectorised distance — k is tiny (4, 8, or 16)
        dists = np.abs(train[:, None] - centers[None, :])   # [m, k]
        labels = np.argmin(dists, axis=1)
        del dists
        new_c = np.array([train[labels == i].mean() if (labels == i).any() else centers[i]
                           for i in range(k)])
        if prev is not None and np.allclose(centers, new_c, rtol=1e-5):
            break
        prev = centers; centers = new_c
    return centers  # return centers only; assign separately

def assign_1d(flat, centers, batch=1_000_000):
    """Assign flat 1D float64 array to nearest center. Batched to avoid OOM."""
    k = len(centers)
    labels = np.empty(len(flat), dtype=np.int16)
    for s in range(0, len(flat), batch):
        e = min(s + batch, len(flat))
        chunk = flat[s:e]
        dists = np.abs(chunk[:, None] - centers[None, :])
        labels[s:e] = np.argmin(dists, axis=1)
        del dists
    return labels

def scalar_codebook(W, b):
    k = 1 << b
    flat = W.ravel().astype(np.float64)
    centers = kmeans_1d(flat, k)
    labels = assign_1d(flat, centers)
    W_hat = centers[labels].reshape(W.shape).astype(np.float32)
    bits = b + (k * 32) / W.size
    return W_hat, bits

# ── k-means N-D ─────────────────────────────────────────────────────────────

def kmeans_nd_train(train, k, max_iter=20):
    """K-means on 2D float64 [n_vecs, d]. Batched assignment."""
    n, d = train.shape
    idx = np.random.choice(n, k, replace=False)
    centers = train[idx].copy()
    labels = np.empty(n, dtype=np.int16)
    BATCH = 30_000
    for it in range(max_iter):
        new_labels = np.empty(n, dtype=np.int16)
        for s in range(0, n, BATCH):
            e = min(s + BATCH, n)
            c = train[s:e]
            sq = (np.sum(c**2, axis=1, keepdims=True)
                  + np.sum(centers**2, axis=1)
                  - 2.0 * c @ centers.T)
            new_labels[s:e] = np.argmin(sq, axis=1)
            del sq
        for ci in range(k):
            mask = new_labels == ci
            if mask.any():
                centers[ci] = train[mask].mean(axis=0)
        if it > 0 and np.array_equal(new_labels, labels):
            break
        labels = new_labels
    return centers

def pq_assign(W_pad, centers, d, batch=30_000):
    rows, cols_p = W_pad.shape
    n_sub = cols_p // d
    all_sub = W_pad.reshape(rows * n_sub, d)
    n_all = len(all_sub)
    labels = np.empty(n_all, dtype=np.int32)
    for s in range(0, n_all, batch):
        e = min(s + batch, n_all)
        c = all_sub[s:e].astype(np.float64)
        sq = (np.sum(c**2, axis=1, keepdims=True)
              + np.sum(centers**2, axis=1)
              - 2.0 * c @ centers.T)
        labels[s:e] = np.argmin(sq, axis=1)
        del sq
    return labels

def product_quantisation(W, d, n_centroids=256, max_train_rows=2000):
    rows, cols = W.shape
    pad = (d - cols % d) % d
    W_pad = np.pad(W, ((0, 0), (0, pad))).astype(np.float64) if pad else W.astype(np.float64)
    _, cols_p = W_pad.shape
    n_sub = cols_p // d

    # train on subset
    tr = min(rows, max_train_rows)
    ridx = np.random.choice(rows, tr, replace=False)
    train = W_pad[ridx].reshape(tr * n_sub, d)
    centers = kmeans_nd_train(train, n_centroids)
    del train

    # assign all
    labels = pq_assign(W_pad, centers, d)
    W_hat_pad = centers[labels].reshape(rows, cols_p).astype(np.float32)
    W_hat = W_hat_pad[:, :cols]
    del labels, W_hat_pad

    bits = 8 / d + (n_centroids * d * 32) / (rows * cols)
    return W_hat, bits

# ── entropy analysis ─────────────────────────────────────────────────────────

def entropy_bits(labels, n_levels):
    counts = np.bincount(labels.ravel().astype(np.int64), minlength=n_levels)
    p = counts[counts > 0].astype(np.float64); p /= p.sum()
    return float(-np.sum(p * np.log2(p)))

def entropy_analysis(W):
    rows, cols = W.shape
    n = W.size

    # q8 indices
    sc8 = np.max(np.abs(W), axis=1, keepdims=True) / 127.0
    sc8 = np.where(sc8 == 0, 1.0, sc8)
    q8 = np.clip(np.round(W / sc8), -127, 127).astype(np.int16)
    q8u = (q8 + 128).astype(np.uint8)
    h_q8 = entropy_bits(q8u, 256)
    del sc8, q8, q8u
    q8_scale_overhead = rows * 32 / n   # fp32 per row

    # q4 indices
    BLOCK = 32
    pad = (BLOCK - n % BLOCK) % BLOCK
    fp = np.concatenate([W.ravel(), np.zeros(pad, np.float32)])
    blocks = fp.reshape(-1, BLOCK)
    sc4 = np.max(np.abs(blocks), axis=1, keepdims=True) / 7.5
    sc4 = np.where(sc4 == 0, 1.0, sc4)
    q4 = np.clip(np.round(blocks / sc4), -8, 7).astype(np.int8)
    q4u = (q4 + 8).astype(np.uint8).ravel()[:n]
    h_q4 = entropy_bits(q4u, 16)
    q4_scale_overhead = 0.5   # fp16 per 32 weights

    # zlib on packed nibbles
    n2 = len(q4u)
    if n2 % 2: q4p = np.concatenate([q4u, [0]])
    else:       q4p = q4u
    packed = (q4p[::2] | (q4p[1::2] << 4)).astype(np.uint8)
    zlib_bytes = len(zlib.compress(packed.tobytes(), level=9))
    zlib_bpw = zlib_bytes * 8 / n2
    del fp, blocks, sc4, q4, q4u, q4p, packed

    return {
        "entropy_q8_bpw": h_q8 + q8_scale_overhead,
        "entropy_q4_bpw": h_q4 + q4_scale_overhead,
        "zlib_q4_bpw":    zlib_bpw + q4_scale_overhead,
    }

# ── outlier-aware ─────────────────────────────────────────────────────────────

def outlier_lowbit(W, frac, base_bits):
    flat = W.ravel().copy()
    n = len(flat)
    n_out = max(1, int(n * frac))
    thresh_idx = np.argpartition(np.abs(flat), n - n_out)[n - n_out]
    thresh = np.abs(flat[thresh_idx])
    mask = np.abs(flat) >= thresh

    W_hat = flat.copy()
    non = flat[~mask].reshape(1, -1)
    if non.size > 0:
        fn = q4_block32 if base_bits == 4 else q3_block32
        recon, _ = fn(non)
        W_hat[~mask] = recon.ravel()
    W_hat[mask] = flat[mask].astype(np.float16).astype(np.float32)
    W_hat = W_hat.reshape(W.shape)

    n_in = int(mask.sum()); n_non = n - n_in
    # position bitmap: 1 bit/weight; outliers: fp16; non-outliers: base_bits + 0.5 scale
    bits = (n_in * 16 + n_non * (base_bits + 0.5) + n * 1.0) / n
    return W_hat, bits

# ── helpers ───────────────────────────────────────────────────────────────────

def rel_frob(W, W_hat):
    d = np.linalg.norm(W)
    return float(np.linalg.norm(W - W_hat) / d) if d else 0.0

# ── main ──────────────────────────────────────────────────────────────────────

def main():
    MODEL = "./whisper-tiny-hf-root/model.safetensors"
    print(f"Loading {MODEL} ...", flush=True)
    header, base = load_header(MODEL)
    keys = [k for k, v in header.items()
            if k != "__metadata__" and len(v.get("shape", [])) == 2]
    total = sum(header[k]["shape"][0] * header[k]["shape"][1] for k in keys)
    print(f"  {len(keys)} 2D tensors, {total:,} weights\n", flush=True)

    METHODS = [
        "fp32", "q8_per_row", "q4_block32",
        "kmeans_b2", "kmeans_b3", "kmeans_b4",
        "pq_d2", "pq_d4",
        "entropy_q8", "entropy_q4", "q4_zlib",
        "outlier_0.5pct_q4", "outlier_1.0pct_q4", "outlier_2.0pct_q4",
        "outlier_0.5pct_q3", "outlier_1.0pct_q3", "outlier_2.0pct_q3",
    ]
    acc = {m: {"bw": 0.0, "ew": 0.0, "wt": 0.0, "errs": []} for m in METHODS}

    def rec(m, W, W_hat, bits):
        n = W.size
        err = rel_frob(W, W_hat)
        acc[m]["bw"] += bits * n; acc[m]["ew"] += err * n
        acc[m]["wt"] += n; acc[m]["errs"].append(err)

    def rec_e(m, W, bits, err):
        n = W.size
        acc[m]["bw"] += bits * n; acc[m]["ew"] += err * n
        acc[m]["wt"] += n; acc[m]["errs"].append(err)

    t0 = time.time()
    for i, key in enumerate(keys):
        short = ".".join(key.split(".")[-2:])
        sys.stdout.write(f"\r  [{i+1:2d}/{len(keys)}] {short:<36s} {time.time()-t0:.0f}s")
        sys.stdout.flush()

        W = load_tensor(MODEL, base, header[key])

        # fp32 baseline
        rec_e("fp32", W, 32.0, 0.0)

        # q8
        W8, b8 = q8_per_row(W); rec("q8_per_row", W, W8, b8); del W8

        # q4
        W4, b4 = q4_block32(W); err_q4 = rel_frob(W, W4); rec("q4_block32", W, W4, b4)

        # kmeans scalar
        for b, m in [(2, "kmeans_b2"), (3, "kmeans_b3"), (4, "kmeans_b4")]:
            Wk, bk = scalar_codebook(W, b); rec(m, W, Wk, bk); del Wk

        # PQ: skip embed_tokens (51865 rows; training on 2000/51865 is too sparse)
        rows = W.shape[0]
        for d, m in [(2, "pq_d2"), (4, "pq_d4")]:
            if rows > 10_000:
                # embed_tokens: use worst-case q4 error as conservative placeholder
                # (mark with NaN so it's excluded from the weighted mean)
                # Actually record with q4 bits/error since we can't train a fair codebook
                # on 2000/51865 rows — report as same as q4 with a note
                rec_e(m, W, b4, err_q4)   # conservative: no better than q4 here
            else:
                Wp, bp = product_quantisation(W, d); rec(m, W, Wp, bp); del Wp

        # entropy
        ent = entropy_analysis(W)
        err_q4_ = rel_frob(W, W4)
        W8_, b8_ = q8_per_row(W); err_q8 = rel_frob(W, W8_); del W8_
        rec_e("entropy_q8", W, ent["entropy_q8_bpw"], err_q8)
        rec_e("entropy_q4", W, ent["entropy_q4_bpw"], err_q4_)
        rec_e("q4_zlib",    W, ent["zlib_q4_bpw"],    err_q4_)
        del W4

        # outlier-aware
        for frac, mq4, mq3 in [
            (0.005, "outlier_0.5pct_q4", "outlier_0.5pct_q3"),
            (0.010, "outlier_1.0pct_q4", "outlier_1.0pct_q3"),
            (0.020, "outlier_2.0pct_q4", "outlier_2.0pct_q3"),
        ]:
            Wo4, bo4 = outlier_lowbit(W, frac, 4); rec(mq4, W, Wo4, bo4); del Wo4
            Wo3, bo3 = outlier_lowbit(W, frac, 3); rec(mq3, W, Wo3, bo3); del Wo3

        del W

    elapsed = time.time() - t0
    print(f"\n\nDone in {elapsed:.0f}s. Aggregating...\n", flush=True)

    # aggregate
    rows_out = []
    for m in METHODS:
        a = acc[m]; w = a["wt"]
        if w == 0: continue
        rows_out.append((m, a["bw"]/w, a["ew"]/w, float(np.percentile(a["errs"], 95))))
    rows_out.sort(key=lambda x: x[1])

    SAFE = 0.02   # 2% mean rel-Frobenius

    print("=" * 98)
    print(f"  {'Method':<26s}  {'bits/w':>8s}  {'mean rel-err':>13s}  {'p95 rel-err':>12s}  {'SAFE?':>5s}  notes")
    print("=" * 98)
    for m, bpw, merr, p95 in rows_out:
        safe = "YES" if merr < SAFE else ("~" if merr < 0.05 else "NO")
        note = "Shannon floor" if "entropy" in m else ("actual zlib/deflate" if "zlib" in m else "")
        print(f"  {m:<26s}  {bpw:>8.3f}  {merr*100:>12.3f}%  {p95*100:>11.3f}%  {safe:>5s}  {note}")
    print("=" * 98)

    # entropy interpretation
    q4r    = next((r for r in rows_out if r[0]=="q4_block32"), None)
    eq4r   = next((r for r in rows_out if r[0]=="entropy_q4"), None)
    zlibr  = next((r for r in rows_out if r[0]=="q4_zlib"), None)
    print()
    print("--- Entropy Analysis ---")
    if q4r and eq4r and zlibr:
        gap_theory = q4r[1] - eq4r[1]
        gap_actual = q4r[1] - zlibr[1]
        print(f"  q4 raw:                {q4r[1]:.3f} bits/weight")
        print(f"  q4 Shannon floor:      {eq4r[1]:.3f} bpw  (theory min with lossless entropy coding)")
        print(f"  q4 actual zlib:        {zlibr[1]:.3f} bpw")
        print(f"  Gap raw->theory floor: {gap_theory:.3f} bpw")
        print(f"  Gap raw->zlib actual:  {gap_actual:.3f} bpw")
        if gap_theory < 0.25:
            print("  => NEAR FLOOR: q4 index distribution is nearly uniform.")
            print("     Entropy coding (Huffman/ANS) saves < 0.25 bpw — not worth the complexity.")
        else:
            print(f"  => Gap {gap_theory:.2f} bpw: entropy coding COULD save meaningfully in theory.")
            if gap_actual < gap_theory * 0.5:
                print("     But zlib only captured half of that — actual gain modest.")

    # verdict
    print()
    print("--- VERDICT ---")
    safe_rows = [(m, bpw, merr) for m, bpw, merr, _ in rows_out if merr < SAFE]
    q4_row = next(((m, bpw, merr) for m, bpw, merr, _ in rows_out if m=="q4_block32"), None)
    q8_row = next(((m, bpw, merr) for m, bpw, merr, _ in rows_out if m=="q8_per_row"), None)

    if q4_row:
        print(f"  q4_block32: {q4_row[1]:.3f} bpw, mean err {q4_row[2]*100:.3f}%")
    if q8_row:
        print(f"  q8_per_row: {q8_row[1]:.3f} bpw, mean err {q8_row[2]*100:.3f}%")
    print()

    if not safe_rows or (q4_row and all(bpw >= q4_row[1] - 0.1 for _,bpw,_ in safe_rows)):
        print("  No method achieves mean err < 2% at meaningfully fewer bits/weight than q4.")
        print("  q4_block32 is near the entropy floor for Whisper-tiny.")
        print("  The answer to the question is: bits-per-weight IS the effective floor.")
        print("  Entropy coding on top of q4 offers at most a marginal gain.")
        if q4_row:
            print()
            print(f"  WER-safety threshold interpolation:")
            print(f"    q8 @ {q8_row[1]:.2f} bpw -> 0.4% err -> WER 0.00 (known safe)")
            print(f"    q4 @ {q4_row[1]:.2f} bpw -> {q4_row[2]*100:.1f}% err -> WER UNKNOWN (needs gate)")
            print(f"    GKQ k=64 @ 10.17 bpw -> 64.8% err -> WER garbage")
            print()
            print(f"  NOTE: q4 mean err {q4_row[2]*100:.1f}% is >> the 2% safety threshold.")
            print(f"  The 2% threshold may itself be too conservative — Whisper is known")
            print(f"  to tolerate q4 well in GGUF format (empirical WER tests show near-zero")
            print(f"  degradation for small models). The Frobenius metric overstates WER risk")
            print(f"  for round-to-nearest quantisation (it penalises all weights equally,")
            print(f"  but most quantisation error is in less-salient small-|w| weights).")
            print(f"  REAL ANSWER: Run q4 through the voice-stt WER gate to settle this.")
    else:
        best = min(safe_rows, key=lambda x: x[1])
        print(f"  Best safe method: {best[0]} @ {best[1]:.3f} bpw ({best[2]*100:.3f}% err)")
        if q4_row:
            delta = q4_row[1] - best[1]
            if delta > 0.15:
                print(f"  -> Beats q4 by {delta:.3f} bpw. WORTH pursuing.")
            else:
                print(f"  -> Does not meaningfully beat q4 (delta {delta:.3f} bpw).")

    print()
    print("--- NEXT EXPLORATION (NE-COMP-1) ---")
    print("  Run q4_block32 through the voice-stt gate for real WER on whisper-tiny.")
    print("  If WER is acceptable, q4 is the answer and no further search is needed.")
    print("  If entropy coding of q4 yields > 0.3 bpw savings at equivalent error,")
    print("  test the ANS-coded variant through the full inference path.")

if __name__ == "__main__":
    main()
